{"code":"import pandas as pd
import json
import re

# Load data
with open(locals()['var_function-call-5473606879443203054'], 'r') as f:
    data = json.load(f)

# Date parser
def parse_date(date_str):
    # Map month names
    months = {
        'january': 1, 'february': 2, 'march': 3, 'april': 4, 'may': 5, 'june': 6,
        'july': 7, 'august': 8, 'september': 9, 'october': 10, 'november': 11, 'december': 12,
        'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6,
        'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12
    }

    if not date_str:
        return None

    s = date_str.lower()
    # Remove suffixes
    s = re.sub(r'(\d+)(st|nd|rd|th)', r'\1', s)
    # Remove filler words
    s = re.sub(r'\b(dated|on|the|of)\b', ' ', s)
    # Replace commas with space
    s = s.replace(',', ' ')

    parts = s.split()

    y, m, d = None, None, None

    # Find Year (4 digits)
    for i, p in enumerate(parts):
        if p.isdigit() and len(p) == 4:
            y = int(p)
            parts.pop(i)
            break

    if y is None: return None

    # Find Month
    for i, p in enumerate(parts):
        if p in months:
            m = months[p]
            parts.pop(i)
            break

    if m is None: return None

    # Find Day
    for p in parts:
        if p.isdigit():
            d = int(p)
            break

    if y and m and d:
        try:
            return pd.Timestamp(year=y, month=m, day=d)
        except:
            return None
    return None

# Filter and Process
counts = {}

for row in data:
    g_date = parse_date(row.get('grant_date'))
    # Filter Grant Date: H2 2019
    if g_date and g_date >= pd.Timestamp('2019-07-01') and g_date <= pd.Timestamp('2019-12-31'):
        f_date = parse_date(row.get('filing_date'))
        if f_date:
            y = f_date.year
            try:
                cpcs = json.loads(row.get('cpc', '[]'))
            except:
                continue

            # Extract Level 4 codes (Classes)
            # Level 4 is 3 chars (e.g., A23)
            classes = set()
            for c in cpcs:
                code = c.get('code', '')
                if len(code) >= 3:
                    cls = code[:3]
                    classes.add(cls)

            for cls in classes:
                if cls not in counts:
                    counts[cls] = {}
                counts[cls][y] = counts[cls].get(y, 0) + 1

# Calculate EMA
results = []
alpha = 0.1

for cls, year_counts in counts.items():
    if not year_counts:
        continue

    min_year = min(year_counts.keys())
    max_year = max(year_counts.keys())
    years = sorted(range(min_year, max_year + 1))

    ema = 0
    best_ema = -1.0
    best_year = None

    first = True
    for y in years:
        cnt = year_counts.get(y, 0)
        if first:
            ema = cnt
            first = False
        else:
            ema = alpha * cnt + (1 - alpha) * ema

        if ema > best_ema:
            best_ema = ema
            best_year = y

    results.append({
        'symbol': cls,
        'best_year': best_year,
        'max_ema': round(best_ema, 4)
    })

# Sort by Max EMA
results.sort(key=lambda x: x['max_ema'], reverse=True)

print("__RESULT__:")
print(json.dumps(results))"}

